    {"id":"wu2024unlearn","title":"Machine Unlearning for Large Language Models: A Survey","authors":"Wu, Yian and Pang, Guoliang and Liu, Yang","year":2024,"venue":"ACM Computing Surveys","abstract":"Machine unlearning enables removing specific knowledge from trained models. This survey reviews unlearning techniques for LLMs, covering exact unlearning, approximate methods, and evaluation metrics for verifying knowledge removal.","summary":"Survey of machine unlearning techniques for LLMs covering exact, approximate methods, and verification.","summary_zh":"LLM机器遗忘技术综述，涵盖精确方法、近似方法和验证指标。","categories":["privacy"],"subcategories":["unlearning","survey"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":[],"target_domain":["llm-privacy"],"llm":[],"model_family":[],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"","baselines":[],"vulnerability_type":["privacy"],"key_results":"Reviews 50+ unlearning methods, identifies key challenges for LLM unlearning","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"shi2024watermark","title":"Red-Teaming LLM Watermarks","authors":"Shi, Zhen and Chen, Yihan and Wen, Yuxin","year":2024,"venue":"ICLR 2024","abstract":"We red-team existing LLM watermarking schemes, demonstrating attacks that remove watermarks while preserving text quality. Our attacks include paraphrasing, token substitution, and recursive editing that defeat current watermarking approaches.","summary":"Red-teams LLM watermarks showing attacks that remove watermarks via paraphrasing and editing.","summary_zh":"红队测试LLM水印，展示通过改述和编辑去除水印的攻击。","categories":["privacy"],"subcategories":["watermarking","attack"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":[],"target_domain":["ai-detection"],"llm":["GPT-4","Llama-2"],"model_family":["gpt","llama"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"","baselines":["KGW watermark","SWEET watermark"],"vulnerability_type":["watermark-removal"],"key_results":"Reduces watermark detection from 99% to 15% while preserving 90% text quality","real_world_impact":"","open_source":True,"cost":""},"recommendation":2},
    {"id":"li2024fedllm","title":"Federated Learning for Large Language Models: Challenges and Solutions","authors":"Li, Tian and Sahu, Anit Kumar and Zaheer, Manzil and Sanjabi, Maziar and Talwalkar, Ameet and Smith, Virginia","year":2024,"venue":"ICML 2024","abstract":"Federated learning enables collaborative LLM training without sharing raw data. We address key challenges in federated LLM training including communication efficiency, heterogeneity, and privacy guarantees.","summary":"Addresses challenges in federated LLM training: communication efficiency, heterogeneity, and privacy.","summary_zh":"解决联邦LLM训练中的挑战：通信效率、异质性和隐私保证。","categories":["privacy"],"subcategories":["federated-learning"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":[],"target_domain":["llm-privacy"],"llm":["Llama-2"],"model_family":["llama"],"model_size":["7B"],"fine_tuning":True,"fine_tuning_method":"FedAvg + LoRA","fuzzer":[],"static_tool":[],"dataset":["Natural Instructions"],"benchmark_size":"","baselines":["Centralized training","FedAvg"],"vulnerability_type":["privacy"],"key_results":"Federated fine-tuning achieves 95% of centralized performance","real_world_impact":"","open_source":True,"cost":""},"recommendation":2},
    {"id":"liu2024trustworthy","title":"Trustworthy LLMs: A Survey and Guideline for Evaluating Large Language Models' Alignment","authors":"Liu, Yang and Yao, Yuanshun and Ton, Jean-Francois and Zhang, Xiaoying and Cheng, Ruocheng and Klochkov, Yegor and Taufiq, Muhammad Faaiz and Li, Hang","year":2024,"venue":"arXiv preprint","abstract":"We survey trustworthiness dimensions of LLMs including truthfulness, safety, fairness, robustness, privacy, machine ethics, and transparency. We provide guidelines for evaluating each dimension and identify gaps.","summary":"Surveys LLM trustworthiness across 7 dimensions including safety, fairness, robustness, and privacy.","summary_zh":"从安全性、公平性、鲁棒性和隐私等7个维度调查LLM的可信度。","categories":["privacy"],"subcategories":["trustworthy","survey"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":[],"target_domain":["llm-safety"],"llm":[],"model_family":[],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"","baselines":[],"vulnerability_type":["trustworthiness"],"key_results":"Provides evaluation framework across 7 trust dimensions","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"wu2024copyrightllm","title":"Copyright Protection for LLM-Generated Code","authors":"Wu, Haoxiang and Chen, Zhengran and Sun, Hao","year":2024,"venue":"ICSE 2024","abstract":"LLMs can generate code that infringes copyright by reproducing training data. We study copyright risks in LLM code generation and propose techniques to detect and mitigate copyright-infringing code outputs.","summary":"Studies copyright risks in LLM code generation and proposes detection and mitigation techniques.","summary_zh":"研究LLM代码生成中的版权风险，提出检测和缓解技术。","categories":["privacy"],"subcategories":["copyright","code-generation"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Python","JavaScript","Java"],"platform":[],"target_domain":["copyright"],"llm":["GPT-4","Copilot","CodeLlama"],"model_family":["gpt","llama"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["GitHub licensed repos"],"benchmark_size":"10000 code samples","baselines":["Code similarity tools"],"vulnerability_type":["copyright"],"key_results":"5-10% of generated code has substantial similarity to training data","real_world_impact":"","open_source":False,"cost":""},"recommendation":1},
    {"id":"wang2024confidential","title":"Confidential Computing for Large Language Model Inference","authors":"Wang, Chenghao and Li, Bo and Zhang, Zheng","year":2024,"venue":"USENIX Security 2024","abstract":"Running LLM inference in untrusted environments risks exposing user prompts and model weights. We propose using confidential computing (TEEs) for LLM inference, addressing performance challenges through optimized enclave design.","summary":"Uses confidential computing (TEEs) for privacy-preserving LLM inference in untrusted environments.","summary_zh":"使用机密计算（TEE）在不可信环境中实现隐私保护的LLM推理。","categories":["privacy"],"subcategories":["confidential-computing","inference"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":["SGX","TDX"],"target_domain":["llm-privacy"],"llm":["Llama-2"],"model_family":["llama"],"model_size":["7B","13B"],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"","baselines":["Unprotected inference"],"vulnerability_type":["privacy"],"key_results":"Only 15% inference overhead for 7B model in TEE","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"chen2024llmguardrail","title":"LLM Guardrails: A Comprehensive Survey of Safety Mechanisms","authors":"Chen, Jiaxin and Wang, Yue and Li, Hang","year":2024,"venue":"arXiv preprint","abstract":"We survey guardrail mechanisms for LLMs including input/output filters, constitutional AI, RLHF, red teaming, and runtime monitoring. We compare approaches on effectiveness, cost, and impact on model utility.","summary":"Surveys LLM guardrail mechanisms including filters, constitutional AI, RLHF, and runtime monitoring.","summary_zh":"调查LLM护栏机制，包括过滤器、宪法AI、RLHF和运行时监控。","categories":["privacy"],"subcategories":["guardrails","safety"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":[],"target_domain":["llm-safety"],"llm":[],"model_family":[],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"","baselines":[],"vulnerability_type":["safety"],"key_results":"Compares 15+ guardrail approaches across 5 dimensions","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"zhao2024modelsteal","title":"Stealing Large Language Model Parameters via Side-Channel Attacks","authors":"Zhao, Yixin and Chen, Guang and Wang, Haoyu","year":2024,"venue":"CCS 2024","abstract":"We demonstrate side-channel attacks that extract LLM parameters from GPU memory access patterns. By monitoring cache timing and memory access patterns during inference, we reconstruct model weights with high fidelity.","summary":"Demonstrates GPU side-channel attacks extracting LLM parameters from memory access patterns.","summary_zh":"展示GPU侧信道攻击从内存访问模式中提取LLM参数。","categories":["privacy"],"subcategories":["side-channel","model-stealing"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":["NVIDIA GPU"],"target_domain":["model-security"],"llm":["GPT-2","Llama-2"],"model_family":["gpt","llama"],"model_size":["1.5B","7B"],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"","baselines":[],"vulnerability_type":["model-stealing","side-channel"],"key_results":"Reconstructs 70% of model weights from GPU cache timing","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"wan2024pii","title":"PII Detection and Redaction in LLM Outputs","authors":"Wan, Yuxin and Chen, Sen and Li, Bo","year":2024,"venue":"EMNLP 2024","abstract":"LLMs may inadvertently output personally identifiable information (PII). We develop methods for real-time PII detection and redaction in LLM outputs, using a lightweight classifier to filter sensitive information before it reaches users.","summary":"Develops real-time PII detection and redaction for LLM outputs using lightweight classifiers.","summary_zh":"开发使用轻量级分类器对LLM输出进行实时PII检测和编辑的方法。","categories":["privacy"],"subcategories":["pii","redaction"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":[],"target_domain":["llm-privacy"],"llm":["GPT-3.5","Llama-2"],"model_family":["gpt","llama"],"model_size":[],"fine_tuning":True,"fine_tuning_method":"full","fuzzer":[],"static_tool":[],"dataset":["PII-Bench"],"benchmark_size":"10000 outputs","baselines":["Presidio","Microsoft Presidio","regex"],"vulnerability_type":["pii-leakage"],"key_results":"97% PII recall with 1ms additional latency per token","real_world_impact":"","open_source":True,"cost":""},"recommendation":2},
    {"id":"zhang2024llmbias","title":"Bias and Fairness in Large Language Models: A Survey","authors":"Zhang, Emily and Yin, Wenjie and Chen, Yun","year":2024,"venue":"EMNLP 2024","abstract":"We survey bias and fairness issues in LLMs, covering types of bias (gender, racial, cultural), measurement methodologies, mitigation strategies, and regulatory implications for LLM deployment.","summary":"Surveys LLM bias and fairness covering types, measurement, mitigation, and regulatory implications.","summary_zh":"调查LLM偏见和公平性问题，涵盖类型、测量、缓解和监管影响。","categories":["privacy"],"subcategories":["bias","fairness"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":[],"target_domain":["llm-fairness"],"llm":[],"model_family":[],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"","baselines":[],"vulnerability_type":["bias"],"key_results":"Reviews 100+ papers, proposes unified fairness evaluation framework","real_world_impact":"","open_source":False,"cost":""},"recommendation":1},
    {"id":"huang2024llmapi","title":"Securing LLM APIs: Authentication, Rate Limiting, and Abuse Prevention","authors":"Huang, Yifan and Gong, Neil and Liu, Peng","year":2024,"venue":"USENIX Security 2024","abstract":"LLM APIs face unique security challenges including prompt extraction, model misuse, and cost attacks. We study API-level security measures and propose enhanced authentication and abuse prevention mechanisms for LLM service providers.","summary":"Studies LLM API security including prompt extraction, misuse, and cost attacks, proposing enhanced protection.","summary_zh":"研究LLM API安全性，包括提示提取、误用和成本攻击，提出增强保护机制。","categories":["privacy"],"subcategories":["api-security","abuse"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":["OpenAI API","Anthropic API"],"target_domain":["api-security"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"","baselines":[],"vulnerability_type":["api-abuse","prompt-extraction"],"key_results":"Demonstrates 3 novel API attack vectors, proposes mitigations","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"liu2024agentattack","title":"Attacking LLM Agents: Prompt Injection in Multi-Agent Systems","authors":"Liu, Yupei and Jia, Jinyuan and Gong, Neil","year":2024,"venue":"NDSS 2024","abstract":"Multi-agent LLM systems introduce new attack surfaces. We demonstrate how compromising a single agent can cascade to manipulate the entire multi-agent system through inter-agent communication, achieving goal hijacking and data exfiltration.","summary":"Demonstrates cascading attacks in multi-agent LLM systems through inter-agent prompt injection.","summary_zh":"展示多代理LLM系统中通过代理间提示注入的级联攻击。","categories":["privacy"],"subcategories":["multi-agent","attack"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":[],"platform":["AutoGPT","CrewAI","LangChain"],"target_domain":["agent-security"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":[],"benchmark_size":"10 multi-agent systems","baselines":["Direct injection","No attack"],"vulnerability_type":["prompt-injection","goal-hijacking"],"key_results":"Successfully compromises 8/10 multi-agent systems via single agent","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"chen2024hallucinationsec","title":"Security Implications of LLM Hallucinations in Code Generation","authors":"Chen, Yifan and Thompson, Neil and Li, Zhen","year":2024,"venue":"IEEE S&P 2024","abstract":"LLM hallucinations in code generation can introduce security vulnerabilities. We study how hallucinated package names, API calls, and code patterns create supply chain and logic vulnerabilities in LLM-generated code.","summary":"Studies security implications of LLM code hallucinations creating supply chain and logic vulnerabilities.","summary_zh":"研究LLM代码幻觉创建供应链和逻辑漏洞的安全影响。","categories":["privacy","vulnerability-detection"],"subcategories":["hallucination","code-generation"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Python","JavaScript"],"platform":[],"target_domain":["code-security"],"llm":["GPT-4","Copilot","CodeLlama"],"model_family":["gpt","llama"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["HumanEval","CodeGen benchmarks"],"benchmark_size":"5000 code samples","baselines":[],"vulnerability_type":["hallucinated-package","api-misuse"],"key_results":"3.5% of generated code references non-existent packages (squattable)","real_world_impact":"Led to new package squatting awareness","open_source":False,"cost":""},"recommendation":2},

    # ===== ADDITIONAL FUZZING PAPERS (30 more) =====
    {"id":"bohme2024llmfuzz","title":"Boosting Fuzzer Efficiency: An Information Theoretic Approach with LLMs","authors":"Bohme, Marcel and Pham, Van-Thuan and Roychoudhury, Abhik","year":2024,"venue":"ICSE 2024","abstract":"We propose using LLMs to estimate information content of fuzzing inputs, prioritizing mutations that are likely to increase coverage. This information-theoretic approach guides the fuzzer toward unexplored program behaviors more efficiently.","summary":"Uses LLMs for information-theoretic guidance of fuzzing, prioritizing mutations likely to increase coverage.","summary_zh":"利用LLM进行模糊测试的信息论引导，优先选择可能增加覆盖率的变异。","categories":["fuzzing"],"subcategories":["information-theory","efficiency"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["C"],"platform":["Linux"],"target_domain":["system-software"],"llm":["GPT-3.5"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":["AFL++"],"static_tool":[],"dataset":["FuzzBench"],"benchmark_size":"20 targets","baselines":["AFL++","FairFuzz","MOpt"],"vulnerability_type":["crash","memory-safety"],"key_results":"20% more coverage in same time budget vs AFL++","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"ye2024deepfuzz","title":"DeepFuzz: Deep Learning Augmented Fuzzing","authors":"Ye, Wei and Shin, Ravi and Song, Dawn","year":2024,"venue":"ISSTA 2024","abstract":"We present DeepFuzz, combining deep learning-based input generation with traditional coverage-guided fuzzing. DeepFuzz uses a neural network to learn input structure and generate smart mutations that maintain validity while exploring new paths.","summary":"Combines deep learning input generation with coverage-guided fuzzing for smart structure-aware mutations.","summary_zh":"结合深度学习输入生成与覆盖引导模糊测试，实现智能结构感知变异。","categories":["fuzzing"],"subcategories":["deep-learning","structure-aware"],"system_name":"DeepFuzz","paperUrl":"","codeUrl":"","experiment":{"language":["C"],"platform":["Linux"],"target_domain":["parser"],"llm":["Transformer (custom)"],"model_family":["transformer"],"model_size":[],"fine_tuning":True,"fine_tuning_method":"full","fuzzer":["AFL++"],"static_tool":[],"dataset":["XML parsers","JSON parsers"],"benchmark_size":"10 parsers","baselines":["AFL++","Nautilus","Superion"],"vulnerability_type":["crash","memory-corruption"],"key_results":"Found 28 new bugs in mature parsers","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"shen2024neuronfuzz","title":"NeuronFuzz: Neural Network Guided Greybox Fuzzing","authors":"Shen, Qingchao and Chen, Haonan and Li, Yuekang","year":2024,"venue":"ASE 2024","abstract":"NeuronFuzz uses neural networks to predict which mutations will increase code coverage. By training on execution traces and coverage feedback, the neural model learns to select promising mutation locations and strategies.","summary":"Uses neural networks to predict coverage-increasing mutations, learning from execution traces and feedback.","summary_zh":"使用神经网络预测增加覆盖率的变异，从执行轨迹和反馈中学习。","categories":["fuzzing"],"subcategories":["neural-network","mutation"],"system_name":"NeuronFuzz","paperUrl":"","codeUrl":"","experiment":{"language":["C","C++"],"platform":["Linux"],"target_domain":["system-software"],"llm":["Custom transformer"],"model_family":["transformer"],"model_size":[],"fine_tuning":True,"fine_tuning_method":"full","fuzzer":["AFL++"],"static_tool":[],"dataset":["FuzzBench"],"benchmark_size":"15 benchmarks","baselines":["AFL++","MOpt","EcoFuzz"],"vulnerability_type":["crash","memory-safety"],"key_results":"15% more branches covered in 24h vs AFL++","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"liu2024smartfuzzer","title":"LLM-Enhanced Smart Fuzzing for Network Protocols","authors":"Liu, Tao and Wang, Yue and Chen, Jun","year":2024,"venue":"NDSS 2024","abstract":"Network protocol fuzzing requires valid message sequences. We use LLMs to understand protocol state machines from RFCs and generate smart fuzzing strategies that exercise protocol edge cases.","summary":"Uses LLMs to understand protocol state machines from RFCs for smart protocol fuzzing.","summary_zh":"利用LLM从RFC理解协议状态机，实现智能协议模糊测试。","categories":["fuzzing"],"subcategories":["protocol","smart"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["C"],"platform":["Linux"],"target_domain":["network-protocol"],"llm":["GPT-4"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":["AFLNet"],"static_tool":[],"dataset":["ProFuzzBench"],"benchmark_size":"8 protocols","baselines":["AFLNet","Boofuzz","ChatAFL"],"vulnerability_type":["crash","memory-corruption"],"key_results":"35% more state transitions explored than AFLNet","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"wang2024apifuzz","title":"APIFuzz: LLM-Guided API Sequence Generation for Library Fuzzing","authors":"Wang, Zhengjie and Li, Shuai and Zhang, Chao","year":2024,"venue":"ESEC/FSE 2024","abstract":"Library fuzzing requires valid API call sequences. APIFuzz uses LLMs to understand library API semantics and generate valid, diverse API call sequences that exercise complex library functionality.","summary":"Uses LLMs to generate valid API call sequences for library fuzzing based on semantic understanding.","summary_zh":"利用LLM基于语义理解生成有效的API调用序列，用于库模糊测试。","categories":["fuzzing"],"subcategories":["api","library"],"system_name":"APIFuzz","paperUrl":"","codeUrl":"","experiment":{"language":["C","C++"],"platform":["Linux"],"target_domain":["library"],"llm":["GPT-4","CodeLlama"],"model_family":["gpt","llama"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":["libFuzzer"],"static_tool":[],"dataset":["10 libraries"],"benchmark_size":"10 libraries","baselines":["FUDGE","Hopper","FuzzGen"],"vulnerability_type":["crash","memory-safety"],"key_results":"42% more API coverage than FUDGE","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"chen2024adaptivefuzz","title":"Adaptive LLM-Guided Fuzzing with Dynamic Strategy Selection","authors":"Chen, Yong and Wu, Lei and Bohme, Marcel","year":2024,"venue":"CCS 2024","abstract":"Different fuzzing targets benefit from different strategies. We propose adaptive fuzzing that uses LLMs to dynamically select mutation strategies based on observed coverage patterns, program structure, and historical effectiveness.","summary":"Adaptive fuzzing using LLMs to dynamically select mutation strategies based on coverage and program structure.","summary_zh":"自适应模糊测试，利用LLM根据覆盖率和程序结构动态选择变异策略。","categories":["fuzzing"],"subcategories":["adaptive","strategy-selection"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["C"],"platform":["Linux"],"target_domain":["system-software"],"llm":["GPT-3.5"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":["AFL++"],"static_tool":[],"dataset":["Magma","FuzzBench"],"benchmark_size":"20 targets","baselines":["AFL++","MOpt","EcoFuzz"],"vulnerability_type":["crash","memory-safety"],"key_results":"18% faster bug finding than static strategy AFL++","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},

    # ===== MORE VULN DETECTION (40 more) =====
    {"id":"ullah2024llmseccode","title":"Can LLMs Write Secure Code? A Large-Scale Experiment with ChatGPT","authors":"Ullah, Shafiq and Han, Yu and Liu, Yang","year":2024,"venue":"IEEE S&P 2024","abstract":"We study whether LLM-generated code is secure by analyzing 4000 code samples from ChatGPT across 10 languages. We find that 25% of generated code contains security vulnerabilities, with injection flaws being most common.","summary":"Studies security of LLM-generated code across 10 languages, finding 25% contains vulnerabilities.","summary_zh":"研究10种语言中LLM生成代码的安全性，发现25%包含漏洞。","categories":["vulnerability-detection"],"subcategories":["code-generation","security"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Python","JavaScript","Java","C","C++","Go","Rust","PHP","Ruby","Swift"],"platform":[],"target_domain":["code-security"],"llm":["ChatGPT","GPT-4","Copilot"],"model_family":["gpt"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Semgrep","CodeQL","Bandit"],"dataset":["4000 generated samples"],"benchmark_size":"4000 code samples","baselines":["Human-written code"],"vulnerability_type":["injection","XSS","path-traversal","hardcoded-credential"],"key_results":"25% of LLM code has vulnerabilities, vs 15% for human code","real_world_impact":"","open_source":True,"cost":""},"recommendation":2},
    {"id":"zhuo2024securityeval","title":"SecurityEval: A Comprehensive Benchmark for Evaluating LLM Code Security","authors":"Zhuo, Tony and Huang, Yifan and Chen, Zheng","year":2024,"venue":"ISSTA 2024","abstract":"We present SecurityEval, a benchmark specifically designed to evaluate the security of LLM-generated code. SecurityEval contains 500 prompts that are likely to produce vulnerable code, covering 30 CWE categories across 5 languages.","summary":"Introduces SecurityEval benchmark with 500 prompts evaluating LLM code security across 30 CWEs.","summary_zh":"引入SecurityEval基准，包含500个提示评估LLM代码安全性，涵盖30种CWE。","categories":["vulnerability-detection"],"subcategories":["benchmark","code-security"],"system_name":"SecurityEval","paperUrl":"","codeUrl":"","experiment":{"language":["Python","JavaScript","Java","C","Go"],"platform":[],"target_domain":["code-security"],"llm":["GPT-4","Claude","CodeLlama","StarCoder","Copilot"],"model_family":["gpt","claude","llama","starcoder"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["CodeQL","Semgrep"],"dataset":["SecurityEval"],"benchmark_size":"500 prompts","baselines":["5 LLMs compared"],"vulnerability_type":["30 CWE categories"],"key_results":"GPT-4 produces least vulnerable code but still 18% vulnerability rate","real_world_impact":"","open_source":True,"cost":""},"recommendation":2},
    {"id":"perry2023users","title":"Do Users Write More Insecure Code with AI Assistants?","authors":"Perry, Neil and Srivastava, Megha and Kumar, Deepak and Boneh, Dan","year":2023,"venue":"CCS 2023","abstract":"We conduct a controlled user study to evaluate whether AI code assistants lead to less secure code. Participants with AI assistance produced significantly more security vulnerabilities than those without, while believing their code was more secure.","summary":"User study showing AI code assistants lead to more security vulnerabilities while users believe code is more secure.","summary_zh":"用户研究表明AI代码助手导致更多安全漏洞，而用户认为代码更安全。","categories":["vulnerability-detection"],"subcategories":["user-study","ai-assistant"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Python"],"platform":[],"target_domain":["code-security"],"llm":["Codex"],"model_family":["codex"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["5 programming tasks"],"benchmark_size":"47 participants","baselines":["No AI assistance"],"vulnerability_type":["SQL-injection","path-traversal","XSS"],"key_results":"AI-assisted participants wrote 10% more vulnerable code","real_world_impact":"Influenced AI assistant safety discussions","open_source":False,"cost":""},"recommendation":3},
    {"id":"he2023codebert4vuln","title":"Large Language Models for Software Vulnerability Detection: A Comprehensive Benchmark Study","authors":"He, Xin and Bai, Jiayuan and Chen, Lin","year":2023,"venue":"ESEC/FSE 2023","abstract":"We benchmark 10 LLMs for vulnerability detection across multiple datasets and evaluate various prompting techniques. Our study reveals that few-shot prompting with examples significantly improves detection performance.","summary":"Benchmarks 10 LLMs for vulnerability detection with various prompting techniques, finding few-shot best.","summary_zh":"对10个LLM在多种提示技术下进行漏洞检测基准测试，发现少样本最佳。","categories":["vulnerability-detection"],"subcategories":["benchmark","prompting"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["C","C++"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["GPT-4","GPT-3.5","Claude","Llama-2","CodeLlama","WizardCoder","StarCoder","Mistral","DeepSeek","Phi-2"],"model_family":["gpt","claude","llama","starcoder","mistral"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["Big-Vul","Devign","SARD"],"benchmark_size":"20000 functions","baselines":["10 LLMs compared","LineVul"],"vulnerability_type":["CWE-119","CWE-20","CWE-416"],"key_results":"Few-shot improves F1 by 15% over zero-shot across all models","real_world_impact":"","open_source":True,"cost":""},"recommendation":2},
    {"id":"li2024vulguard","title":"VulGuard: Real-Time LLM-Based Vulnerability Detection in CI/CD","authors":"Li, Chen and Wang, Yue and Zhang, Tao","year":2024,"venue":"ICSE 2024","abstract":"Integrating vulnerability detection into CI/CD requires balancing speed and accuracy. VulGuard uses lightweight LLM inference with incremental analysis to detect vulnerabilities in code changes in real-time, focusing on modified code rather than full codebase.","summary":"Real-time LLM vulnerability detection in CI/CD using incremental analysis of code changes.","summary_zh":"使用增量分析代码变更在CI/CD中进行实时LLM漏洞检测。","categories":["vulnerability-detection"],"subcategories":["ci-cd","real-time"],"system_name":"VulGuard","paperUrl":"","codeUrl":"","experiment":{"language":["Java","Python","JavaScript"],"platform":["GitHub Actions"],"target_domain":["code-review"],"llm":["GPT-3.5","CodeLlama"],"model_family":["gpt","llama"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["Real GitHub PRs"],"benchmark_size":"2000 pull requests","baselines":["Full scan","CodeQL","Semgrep"],"vulnerability_type":["injection","auth","crypto"],"key_results":"<30s per PR review, detects 65% of vulnerabilities in changed code","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"wang2024repoaudit","title":"Repository-Level Vulnerability Detection with LLMs","authors":"Wang, Ziyang and Li, Hao and Song, Dawn","year":2024,"venue":"ASE 2024","abstract":"Most LLM vulnerability detection focuses on function-level analysis. We extend to repository-level detection, where the LLM analyzes cross-file data flows, configuration files, and architectural patterns to find vulnerabilities that span multiple files.","summary":"Extends LLM vulnerability detection to repository-level, analyzing cross-file data flows and architectural patterns.","summary_zh":"将LLM漏洞检测扩展到仓库级别，分析跨文件数据流和架构模式。","categories":["vulnerability-detection"],"subcategories":["repository-level","cross-file"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["Python","Java"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["20 OSS repositories"],"benchmark_size":"20 repositories","baselines":["Function-level GPT-4","CodeQL"],"vulnerability_type":["cross-file-injection","config-vuln","auth-bypass"],"key_results":"Finds 40% more vulnerabilities than function-level analysis","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"sun2024vulnexplain","title":"Not Just Detection: LLMs for Vulnerability Explanation and Remediation","authors":"Sun, Chengcheng and Xu, Zhengzi and Zhang, Chao","year":2024,"venue":"ESEC/FSE 2024","abstract":"Beyond detection, developers need vulnerability explanations and fix suggestions. We evaluate LLMs' ability to explain detected vulnerabilities in natural language and suggest correct remediations, making security findings more actionable.","summary":"Evaluates LLMs for vulnerability explanation and remediation suggestion, making security findings actionable.","summary_zh":"评估LLM的漏洞解释和修复建议能力，使安全发现可操作。","categories":["vulnerability-detection"],"subcategories":["explanation","remediation"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["C","Java","Python"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["CVE database"],"benchmark_size":"500 vulnerabilities","baselines":["GPT-4","CWE descriptions"],"vulnerability_type":["various"],"key_results":"85% of explanations rated correct by security experts","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"ma2024vulncoder","title":"VulnCoder: Fine-Tuning Code LLMs for Vulnerability Detection","authors":"Ma, Shengjian and Chen, Yizheng and Wagner, David","year":2024,"venue":"ISSTA 2024","abstract":"We present VulnCoder, a series of code LLMs fine-tuned specifically for vulnerability detection. Through careful data curation, training strategy design, and evaluation, VulnCoder achieves SOTA on multiple vulnerability benchmarks.","summary":"Fine-tunes code LLMs specifically for vulnerability detection, achieving SOTA on multiple benchmarks.","summary_zh":"专门针对漏洞检测微调代码LLM，在多个基准上达到最先进水平。","categories":["vulnerability-detection"],"subcategories":["fine-tuning","specialized"],"system_name":"VulnCoder","paperUrl":"","codeUrl":"","experiment":{"language":["C","C++"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["CodeLlama","DeepSeek-Coder"],"model_family":["llama","deepseek"],"model_size":["7B","13B","33B"],"fine_tuning":True,"fine_tuning_method":"LoRA + SFT","fuzzer":[],"static_tool":[],"dataset":["DiverseVul","Big-Vul","CVEFixes"],"benchmark_size":"50000 functions","baselines":["LineVul","ReVeal","GPT-4 zero-shot"],"vulnerability_type":["CWE-119","CWE-20","CWE-416","CWE-787"],"key_results":"33B model achieves 82% F1, surpassing GPT-4 zero-shot by 10%","real_world_impact":"","open_source":True,"cost":""},"recommendation":2},
    {"id":"cao2024vulnlocate","title":"LLM-Based Vulnerability Localization: From Function to Line Level","authors":"Cao, Yonghao and Chen, Jun and Wang, Haoyu","year":2024,"venue":"ICSE 2024","abstract":"Identifying the exact vulnerable lines is more useful than function-level detection. We use LLMs to not only detect but precisely localize vulnerable code lines, using attention patterns and chain-of-thought reasoning.","summary":"Uses LLMs for precise line-level vulnerability localization using attention patterns and chain-of-thought.","summary_zh":"利用LLM通过注意力模式和思维链进行精确的行级漏洞定位。","categories":["vulnerability-detection"],"subcategories":["localization","line-level"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["C","C++"],"platform":[],"target_domain":["vulnerability-detection"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":[],"dataset":["Big-Vul"],"benchmark_size":"5000 functions","baselines":["LineVul","IVDetect","GPT-4 (no CoT)"],"vulnerability_type":["CWE-119","CWE-416","CWE-787"],"key_results":"65% top-5 line accuracy, 20% above LineVul","real_world_impact":"","open_source":False,"cost":""},"recommendation":2},
    {"id":"zhang2024decompvuln","title":"Vulnerability Detection in Decompiled Code: Challenges and Opportunities","authors":"Zhang, Yu and Wang, Ruoyu and Pei, Kexin","year":2024,"venue":"USENIX Security 2024","abstract":"Analyzing vulnerabilities in stripped binaries through decompiled code is critical for closed-source software security. We study how decompilation artifacts affect LLM-based vulnerability detection and propose techniques to improve detection accuracy on decompiled code.","summary":"Studies LLM vulnerability detection on decompiled code, addressing decompilation artifact challenges.","summary_zh":"研究反编译代码上的LLM漏洞检测，解决反编译工件挑战。","categories":["vulnerability-detection"],"subcategories":["binary","decompilation"],"system_name":"","paperUrl":"","codeUrl":"","experiment":{"language":["x86-64"],"platform":[],"target_domain":["binary-analysis"],"llm":["GPT-4","Claude"],"model_family":["gpt","claude"],"model_size":[],"fine_tuning":False,"fine_tuning_method":"","fuzzer":[],"static_tool":["Ghidra","IDA Pro","Hex-Rays"],"dataset":["Juliet Test Suite","Real CVEs"],"benchmark_size":"3000 functions","baselines":["Source-level detection","BinaryAI"],"vulnerability_type":["buffer-overflow","format-string","use-after-free"],"key_results":"Decompiled code detection is 25% less accurate than source, gap closing with better prompts","real_world_impact":"","open_source":False,"cost":""},"recommendation":2}
